1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_PREMIUMS: Record<string, number> = {
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	function calculateBasePremium(items: any[]): number {
18	  const componentCounts: Record<string, number> = {};
19	  let premium = 0;
20	  for (const item of items) {
21	    if (item.type in COMPONENT_PREMIUMS) {
22	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
23	    } else {
24	      premium += MAIN_ITEM_PREMIUMS[item.type];
25	    }
26	  }
27	  for (const [type, count] of Object.entries(componentCounts)) {
28	    premium += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUMS[type];
29	  }
30	  return premium;
31	}
32	
33	const CURSED_SURCHARGE_RATE = 0.5;
34	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	
37	function calculateSingleItemSurcharge(item: any): number {
38	  const basePremium = MAIN_ITEM_PREMIUMS[item.type] || 0;
39	  let surcharge = 0;
40	  if (item.cursed) {
41	    surcharge += basePremium * CURSED_SURCHARGE_RATE;
42	  }
43	  if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
44	    surcharge += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
45	  }
46	  return surcharge;
47	}
48	
49	function calculateItemSurcharges(items: any[]): number {
50	  return items.reduce((total, item) => total + calculateSingleItemSurcharge(item), 0);
51	}
52	
53	export function processScenario(scenario: any): any {
54	  const results = scenario.steps.map((step: any) => {
55	    const basePremium = calculateBasePremium(step.items);
56	    const itemSurcharges = calculateItemSurcharges(step.items);
57	    const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
58	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
59	    const premium = basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE;
60	    return { premium };
61	  });
62	  return { results };
63	}
